// Three single-responsibility protocols
public protocol CacheReading: Sendable {
    func value(forKey key: String) async -> Data?
}

public protocol CacheWriting: Sendable {
    func setValue(_ data: Data, forKey key: String, ttl: TimeInterval) async throws
}

public protocol CacheInvalidating: Sendable {
    var invalidationStream: AsyncStream<String> { get }
}

/// Composite protocol combining all cache client capabilities.
public typealias CacheClientProviding = CacheReading & CacheWriting & CacheInvalidating

public protocol CacheManaging: Observable {
    func bootstrap() async throws
    func value<T: Decodable & Sendable>(forKey key: String) async -> T?
    func store<T: Encodable & Sendable>(_ value: T, forKey key: String, ttl: TimeInterval) async throws
}

@Observable
public final class CacheManager: @unchecked Sendable {

    // MARK: - Private Properties

    private let client: CacheClientProviding
    private var isReady = false

    // MARK: - Initialization

    public init(client: CacheClientProviding) {
        self.client = client
    }
}

// MARK: - CacheManaging

extension CacheManager: CacheManaging {

    public func bootstrap() async throws {
        guard !isReady else { return }
        // warm the client here
        isReady = true
    }

    public func value<T: Decodable & Sendable>(forKey key: String) async -> T? {
        guard let data = await client.value(forKey: key) else { return nil }
        return try? JSONDecoder().decode(T.self, from: data)
    }

    public func store<T: Encodable & Sendable>(_ value: T, forKey key: String, ttl: TimeInterval) async throws {
        let data = try JSONEncoder().encode(value)
        try await client.setValue(data, forKey: key, ttl: ttl)
    }
}

// MARK: - Factory

extension CacheManager {

    public static func live(url: URL) -> CacheManager {
        CacheManager(client: DiskCacheClient(url: url))
    }

    public static var mock: CacheManager {
        CacheManager(client: MockCacheClient())
    }
}

