public final class MockCacheClient: @unchecked Sendable {

    // MARK: - Configurable Values

    public var storedData: [String: Data] = [:]

    // MARK: - State

    public private(set) var readCount = 0
    public private(set) var writeCount = 0
    public private(set) var lastWrittenKey: String?

    // MARK: - Invalidation Stream

    private var invalidationContinuation: AsyncStream<String>.Continuation?
    public let invalidationStream: AsyncStream<String>

    // MARK: - Initialization

    public init() {
        var continuation: AsyncStream<String>.Continuation?
        self.invalidationStream = AsyncStream { continuation = $0 }
        self.invalidationContinuation = continuation
    }

    // MARK: - Test Helpers

    public func simulateInvalidation(key: String) {
        invalidationContinuation?.yield(key)
    }
}

// MARK: - CacheReading

extension MockCacheClient: CacheReading {
    public func value(forKey key: String) async -> Data? {
        readCount += 1
        return storedData[key]
    }
}

// MARK: - CacheWriting

extension MockCacheClient: CacheWriting {
    public func setValue(_ data: Data, forKey key: String, ttl: TimeInterval) async throws {
        writeCount += 1
        lastWrittenKey = key
        storedData[key] = data
    }
}

// MARK: - CacheInvalidating

extension MockCacheClient: CacheInvalidating {}

public actor DiskCacheClient {

    // MARK: - Private Properties

    private let url: URL
    private let fileManager: FileManager

    private var invalidationContinuation: AsyncStream<String>.Continuation?
    nonisolated public let invalidationStream: AsyncStream<String>

    // MARK: - Initialization

    public init(url: URL, fileManager: FileManager = .default) {
        self.url = url
        self.fileManager = fileManager

        var continuation: AsyncStream<String>.Continuation?
        self.invalidationStream = AsyncStream { continuation = $0 }
        self.invalidationContinuation = continuation
    }
}

// MARK: - CacheReading

extension DiskCacheClient: CacheReading {

    public func value(forKey key: String) async -> Data? {
        let fileURL = url.appendingPathComponent(key)
        return try? Data(contentsOf: fileURL)
    }
}

// MARK: - CacheWriting

extension DiskCacheClient: CacheWriting {

    public func setValue(_ data: Data, forKey key: String, ttl: TimeInterval) async throws {
        try fileManager.createDirectory(at: url, withIntermediateDirectories: true)
        let fileURL = url.appendingPathComponent(key)
        try data.write(to: fileURL)
    }
}

// MARK: - CacheInvalidating

extension DiskCacheClient: CacheInvalidating {}

