Rewrite this code to match Chris's preferred pattern:

```swift
struct ProfileView: View {
    @StateObject private var viewModel = ProfileViewModel()
    @EnvironmentObject var userService: UserService

    var body: some View {
        Text(viewModel.name)
            .task {
                viewModel.userService = userService
                await viewModel.load()
            }
    }
}
```

ideal_response:
The anti-patterns here are: `@StateObject` with parameterless init, `@EnvironmentObject`, late dependency injection in `.task`, and mutable property injection on the view model. The Chris-preferred rewrite:

```swift
struct ProfileView: View {

    let userService: any UserService
    @State private var viewModel: ProfileViewModel

    init(userService: any UserService) {
        self.userService = userService
        _viewModel = State(
            wrappedValue: ProfileViewModel(userService: userService)
        )
    }

    var body: some View {
        Text(viewModel.name)
            .task { await viewModel.load() }
    }
}

@Observable
final class ProfileViewModel {

    // MARK: - Private Properties

    private let userService: any UserService

    // MARK: - Public Properties

    private(set) var name: String = ""

    // MARK: - Initialization

    init(userService: any UserService) {
        self.userService = userService
    }

    func load() async {
        name = await userService.currentUserName
    }
}
```

And in `App.swift` the `UserService` is injected both via init (for the root view) and via `.environment(\.userService, userService)` so VM-less leaf views can still read it.

